4288             InstOp, Op, RepOp, Q, AllowRefinement, MaxRecurse)) {
4289       NewOps.push_back(NewInstOp);
4290       AnyReplaced = InstOp != NewInstOp;
4291     } else {
4292       NewOps.push_back(InstOp);
