4466   // (X >  Y) ? X : max(X, Y) --> max(X, Y)
4467   // (X >= Y) ? X : max(X, Y) --> max(X, Y)
4468   // (X <  Y) ? X : min(X, Y) --> min(X, Y)
4469   // (X <= Y) ? X : min(X, Y) --> min(X, Y)
