4492   // (X <= Y) ? X : max(X, Y) --> X
4493   // (X >  Y) ? X : min(X, Y) --> X
4494   // (X >= Y) ? X : min(X, Y) --> X
4495   ICmpInst::Predicate InvPred = CmpInst::getInversePredicate(Pred);
4496   if (MMPred == CmpInst::getStrictPredicate(InvPred))
