4517 /// integer equality comparison.
4518 static Value *simplifySelectWithICmpEq(Value *CmpLHS, Value *CmpRHS,
4519                                        Value *TrueVal, Value *FalseVal,
4520                                        const SimplifyQuery &Q,
4521                                        unsigned MaxRecurse) {
